  ('generalpolice-94737317-moex-00087', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '關於有限公司之董事，下列敘述何者錯誤？', '["有限公司董事一定是該公司之股東", "董事為自己或他人為與公司同類業務之行為，應對全體股東說明其行為之重要內容，並經股東表決 權3分之2以上之同意", "董事不得將自己之出資轉讓給其他人", "除與公司有特別約定外，董事不得向公司請求報酬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
